mapper.select:
select * from classBBS where 1 = 1
and cStatus < 3
and cOnoff = #{onoff}
and cCategory = #{category}
order by cNum desc

select *
from classBBS
where cStatus < 3

    and cOnoff = #{onoff}


    and cCategory = #{category}

order by cLikes desc, cNum desc
limit #{limit}

mapper.insert:
insert into classBBS (
    cCode, cTeacher, cUid, cCategory, cTitle, cContent, cRegDate, cPrice, cDelivery,
    cThumbName, cThumbSize, cFileName, cFileSize, cMaxStu, cApplyStu, cArea, cOnoff, cStatus, cLikes
) values (
    #{cCode}, #{cTeacher}, #{cUid}, #{cCategory}, #{cTitle}, #{cContent}, now(), #{cPrice}, #{cDelivery},
    #{cThumbName}, #{cThumbSize}, #{cFileName}, #{cFileSize}, #{cMaxStu}, #{cApplyStu}, #{cArea}, #{cOnoff}, #{cStatus}, #{cLikes}
)
